   610→    private func scrollRange(for insets: NSEdgeInsets) -> ScrollRange? {
   611→        let clipView = scrollView.contentView
   612→        let visibleSize = clipView.bounds.size
   613→        let docSize = dualPageView.frame.size
   614→
   615→        guard visibleSize.width > 0, visibleSize.height > 0,
   616→              docSize.width > 0, docSize.height > 0 else { return nil }
   617→
   618→        let minX = -insets.left
   619→        // NSScrollView contentInsets 以視覺邊緣為語意：.top = visual top, .bottom = visual bottom
   620→        // unflipped 座標下 visual top = high Y (maxY), visual bottom = low Y (minY)
   621→        let minY = -insets.bottom
   622→        let maxX = max(docSize.width - visibleSize.width + insets.right, minX)
   623→        let maxY = max(docSize.height - visibleSize.height + insets.top, minY)
   624→        return ScrollRange(minX: minX, maxX: maxX, minY: minY, maxY: maxY)
   625→    }
