  1593→    private func schedulePostMagnifyCentering(for phase: NSEvent.Phase) {
  1594→        postMagnifyCenteringTask?.cancel()
  1595→        let shouldFinalize = phase.contains(.ended) || phase.contains(.cancelled)
  1596→        guard shouldFinalize else {
  1597→            DebugCentering.log("magnify deferred centering skipped phase=\(debugPhase(phase))")
  1598→            return
  1599→        }
  1600→        let phaseText = debugPhase(phase)
  1601→        let task = DispatchWorkItem { [weak self] in
  1602→            guard let self else { return }
  1603→            DebugCentering.log("magnify deferred finalize phase=\(phaseText)")
  1604→            // 只做 insets 更新 + clamp，不做 centerScrollPositionInValidRange()
  1605→            // 以保留用戶的 pan 位置
  1606→            self.applyCenteringInsetsIfNeeded(reason: "magnify.deferred.phase=\(phaseText)")
  1607→            self.isZooming = false
  1608→        }
  1609→        postMagnifyCenteringTask = task
  1610→        // 讓 AppKit magnify 事件鏈先落地，再做一次保底 clamp。
  1611→        DispatchQueue.main.async(execute: task)
